from dataclasses import dataclass
from typing import List

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a politician into a readable sentence."""
    if not triples:
        return ""

    # Get the main subject from the first triple
    main_subject = triples[0].subject

    # Create a mapping of predicates to their values
    predicate_map = {}
    for t in triples:
        if t.predicate not in predicate_map:
            predicate_map[t.predicate] = []
        predicate_map[t.predicate].append(t.object)

    # Build a coherent complex sentence
    parts = []

    # Start with identity and profession
    identity_parts = []
    if 'nationality' in predicate_map:
        identity_parts.append(f"{main_subject} is a {predicate_map['nationality'][0]} politician")
    elif 'profession' in predicate_map:
        identity_parts.append(f"{main_subject} is a {predicate_map['profession'][0]}")
    else:
        identity_parts.append(main_subject)

    # Add party affiliation if available
    if 'party' in predicate_map:
        identity_parts[0] += f" from the {predicate_map['party'][0]}"
    parts.append(identity_parts[0])

    # Build relative clause for birth information
    birth_clause = []
    if 'birthDate' in predicate_map:
        birth_clause.append(f"born on {predicate_map['birthDate'][0]}")
    elif 'birthYear' in predicate_map:
        birth_clause.append(f"born in {predicate_map['birthYear'][0]}")
    if 'birthPlace' in predicate_map:
        birth_clause.append(f"in {predicate_map['birthPlace'][0]}")

    # Build career information
    career_parts = []
    if 'office' in predicate_map:
        career_parts.append(f"who served as {predicate_map['office'][0]}")
    if 'inOfficeWhilePresident' in predicate_map:
        career_parts.append(f"during the presidency of {predicate_map['inOfficeWhilePresident'][0]}")
    if 'inOfficeWhilePrimeMinister' in predicate_map:
        career_parts.append(f"during the prime ministership of {predicate_map['inOfficeWhilePrimeMinister'][0]}")
    if 'inOfficeWhileGovernor' in predicate_map:
        career_parts.append(f"during the governorship of {predicate_map['inOfficeWhileGovernor'][0]}")
    if 'inOfficeWhileMonarch' in predicate_map:
        career_parts.append(f"during the reign of {predicate_map['inOfficeWhileMonarch'][0]}")
    if 'inOfficeWhileVicePresident' in predicate_map:
        career_parts.append(f"during the vice presidency of {predicate_map['inOfficeWhileVicePresident'][0]}")

    # Add predecessor/successor information
    if 'predecessor' in predicate_map:
        career_parts.append(f"previously held by {predicate_map['predecessor'][0]}")
    if 'successor' in predicate_map:
        career_parts.append(f"succeeded by {predicate_map['successor'][0]}")

    # Add military service if available
    military_parts = []
    if 'militaryBranch' in predicate_map:
        military_parts.append(f"served in the {predicate_map['militaryBranch'][0]}")
    if 'militaryRank' in predicate_map:
        military_parts.append(f"with the rank of {predicate_map['militaryRank'][0]}")
    if 'battle' in predicate_map:
        military_parts.append(f"and participated in the {predicate_map['battle'][0]}")
    if 'unit' in predicate_map:
        military_parts.append(f"with the {predicate_map['unit'][0]} unit")

    # Add education information
    if 'almaMater' in predicate_map:
        military_parts.append(f"and studied at {predicate_map['almaMater'][0]}")

    # Add personal information
    personal_parts = []
    if 'spouse' in predicate_map:
        personal_parts.append(f"married to {predicate_map['spouse'][0]}")
    if 'residence' in predicate_map:
        personal_parts.append(f"residing in {predicate_map['residence'][0]}")
    if 'religion' in predicate_map:
        personal_parts.append(f"and was a {predicate_map['religion'][0]}")
    if 'award' in predicate_map:
        personal_parts.append(f"and received the {predicate_map['award'][0]}")

    # Add location information
    location_parts = []
    if 'country' in predicate_map:
        location_parts.append(f"from {predicate_map['country'][0]}")
    if 'state' in predicate_map:
        location_parts.append(f"in {predicate_map['state'][0]}")
    if 'region' in predicate_map:
        location_parts.append(f"in the {predicate_map['region'][0]} region")

    # Add death information if available
    death_clause = []
    if 'deathDate' in predicate_map:
        death_clause.append(f"died on {predicate_map['deathDate'][0]}")
    elif 'deathYear' in predicate_map:
        death_clause.append(f"died in {predicate_map['deathYear'][0]}")
    if 'deathPlace' in predicate_map:
        death_clause.append(f"in {predicate_map['deathPlace'][0]}")

    # Add hasDeputy information
    if 'hasDeputy' in predicate_map:
        career_parts.append(f"with deputy {predicate_map['hasDeputy'][0]}")

    # Combine all parts
    all_parts = [parts[0]]
    if birth_clause:
        all_parts.append(f", {' '.join(birth_clause)}")
    if career_parts:
        all_parts.append(f", {' '.join(career_parts)}")
    if military_parts:
        all_parts.append(f", {' '.join(military_parts)}")
    if personal_parts:
        all_parts.append(f", {' '.join(personal_parts)}")
    if location_parts:
        all_parts.append(f", {' '.join(location_parts)}")
    if death_clause:
        all_parts.append(f", {' '.join(death_clause)}")

    # Join and format the final sentence
    result = ' '.join(all_parts)
    return result + "."

# EVOLVE-BLOCK-END
